args.sparql:
SELECT ?person ?personLabel ?partyLabel WHERE { 
  ?person wdt:P69 wd:Q49210; 
  wdt:P569 ?birthDate; 
  wdt:P39 wd:Q418158; 
  wdt:P102 ?party. 
  ?party rdfs:label ?partyLabel. 
  ?person rdfs:label ?personLabel. 
  FILTER(LANG(?partyLabel) = "en" && LANG(?personLabel) = "en"). 
  FILTER(YEAR(?birthDate) >= 1914 && YEAR(?birthDate) <= 1918).
}

SELECT ?person ?personLabel ?partyLabel WHERE {
  ?person wdt:P69 wd:Q49210;
          wdt:P569 ?birthDate;
          wdt:P39 wd:Q418158;
          wdt:P102 ?party.
  ?party rdfs:label ?partyLabel.
  ?person rdfs:label ?personLabel.
  FILTER(LANG(?partyLabel) = "en" && LANG(?personLabel) = "en").
  FILTER(xsd:integer(SUBSTR(STR(?birthDate), 1, 4)) >= 1914 && xsd:integer(SUBSTR(STR(?birthDate), 1, 4)) <= 1918).
}

SELECT ?partyLabel WHERE {
  ?person wdt:P69 wd:Q49210;
          wdt:P569 ?birthDate;
          wdt:P39 wd:Q154847;
          wdt:P102 ?party.
  ?party rdfs:label ?partyLabel.
  FILTER(LANG(?partyLabel) = "en").
